market.service.url=http://localhost:8081
# In prod with Eureka: omit url= and let discovery handle it
```

concept_explanation.feign_error_handling:
**Handling Feign errors вЂ” the right way:**

```java
import feign.Response;
import feign.codec.ErrorDecoder;
import org.springframework.http.HttpStatus;

// Custom error decoder вЂ” maps HTTP status codes to exceptions:
public class MarketServiceErrorDecoder implements ErrorDecoder {

    @Override
    public Exception decode(String methodKey, Response response) {
        HttpStatus status = HttpStatus.resolve(response.status());

        if (status == null) return new RuntimeException("Unknown error: " + response.status());

        return switch (status) {
            case NOT_FOUND -> new SymbolNotFoundException(
                "Symbol not found (from market-service)");
            case CONFLICT -> new OrderConflictException(
                "Order conflict in market-service");
            case BAD_REQUEST -> new IllegalArgumentException(
                "Invalid request to market-service");
            case SERVICE_UNAVAILABLE -> new MarketServiceUnavailableException(
                "Market service is unavailable");
            default -> new RuntimeException(
                "Market service error: " + response.status());
        };
    }
}

// Register in @Configuration:
@Configuration
public class FeignConfig {
    @Bean
    public ErrorDecoder marketServiceErrorDecoder() {
        return new MarketServiceErrorDecoder();
    }
}
```

**Or simpler вЂ” per-client configuration:**
```java
@FeignClient(name = "market-service",
             url = "${market.service.url}",
             configuration = FeignConfig.class)  // apply to this client only
public interface MarketServiceClient { ... }
```

