import org.springframework.cloud.openfeign.FeignClient;
import org.springframework.web.bind.annotation.*;

@FeignClient(
    name = "market-service",
    url = "${market.service.url:http://localhost:8081}",
    configuration = MarketFeignConfig.class
)
public interface MarketServiceClient {

    @GetMapping("/api/stocks/{symbol}/quote")
    StockQuote getQuote(@PathVariable String symbol,
                         @RequestParam String currency);

    @GetMapping("/api/stocks")
    List<StockDto> listAll();

    @PostMapping("/api/market/orders")
    MarketOrderResult submitOrder(@RequestBody MarketOrderRequest req);
}
```

```java
@Configuration
public class MarketFeignConfig {
    @Bean
    ErrorDecoder errorDecoder() {
        return (methodKey, response) -> {
            int status = response.status();
            if (status == 404) return new SymbolNotFoundException("Symbol not found");
            if (status == 503) return new ServiceUnavailableException("Market service down");
            return new RuntimeException("Market service error: " + status);
        };
    }
}
```

```java
@Service
public class TradeService {
    private final MarketServiceClient marketClient;  // Feign interface injected
    private final TradeOrderRepository repo;

    TradeService(MarketServiceClient marketClient, TradeOrderRepository repo) {
        this.marketClient = marketClient; this.repo = repo;
    }

    public TradeOrder executeTrade(String symbol, int qty) {
        // Clean, no URL building, no try-catch per call:
        StockQuote quote = marketClient.getQuote(symbol, "INR");
        if (!quote.tradeable()) throw new IllegalStateException(symbol + " not tradeable");
        return repo.save(new TradeOrder(symbol, qty, quote.price()));
    }
}
```

